toolCalls.args:
{"command": "cd /tmp/sv-ecccdfba20404bb3b7608b2525c98f73 && \
# Try with readelf to get function symbols with sizes
aarch64-linux-gnu-readelf -sW libmonosgen-2.0.so.dbg 2>/dev/null | awk '/FUNC/ {
  addr = strtonum("0x"$2)
  size = strtonum($3)
  end = addr + size
  if (addr <= 0x2f4b20 && 0x2f4b20 < end) printf "0x2f4b20 in: %s (0x%x-0x%x, +0x%x)\n", $8, addr, end, 0x2f4b20-addr
  if (addr <= 0x2f4c84 && 0x2f4c84 < end) printf "0x2f4c84 in: %s (0x%x-0x%x, +0x%x)\n", $8, addr, end, 0x2f4c84-addr
}'", "description": "Find SGen functions via readelf", "initial_wait": 30}

{"command": "cd /tmp/sv-ecccdfba20404bb3b7608b2525c98f73 && \
# Check which section these addresses fall in
aarch64-linux-gnu-readelf -S libmonosgen-2.0.so.dbg 2>/dev/null | head -40 && \
echo "---" && \
# Also get all symbols near these addresses
aarch64-linux-gnu-nm -n -C libmonosgen-2.0.so.dbg 2>/dev/null | awk '{
  addr = strtonum("0x"$1)
  if (addr >= 0x2f4000 && addr <= 0x2f5000) print
}' | head -20", "description": "Check sections and nearby symbols", "initial_wait": 15}
